using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // [Fix 1] Keep "Discriminator" as the JSON property name (EF9 defaults to "$type")
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // [Fix 2] Keep discriminator prefix in JSON id ("Blog|1" format, EF9 drops it)
        modelBuilder.Entity<Blog>().HasDiscriminatorInJsonId();

        // [Fix 3] Keep the shadow __id property so CLR Id stays the logical key
        //         (EF9 maps Id directly to JSON "id", breaking existing key values)
        modelBuilder.Entity<Blog>().HasShadowId();

        // [Fix 4] Removed HasIndex — EF9 Cosmos provider throws instead of ignoring it.
        //         Cosmos indexes all properties by default; configure via Azure Portal if needed.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

